export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "手機螢幕亮了。", background: Background.Chapter_1_Ch1_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是鬧鐘，是那種自己醒過來的亮——沒有聲音，沒有震動，只是螢幕從黑裡浮上來，像水底冒出的一盞燈。朝倉澪睜開眼的時候，夢還黏在眼皮內側，摳不掉。", background: Background.Chapter_1_Ch1_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "夢裡沒有劇情，只有幾個模糊的東西。", background: Background.Chapter_1_Ch1_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一片黑色的海面，平得像沒有人碰過的墨。", background: Background.Chapter_1_Ch1_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "遠處有一個白色的東西，形狀像月亮，但是倒過來的——月牙朝下，像誰把它掛反了。", background: Background.Chapter_1_Ch1_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後是一瞬間的白。無聲。整片海面被照亮又熄掉，快得像沒發生過。", background: Background.Chapter_1_Ch1_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "有人在叫她。", background: Background.Chapter_1_Ch1_Act1_S0 },
    { characterId: CharacterId.DreamVoice, character: "夢話", dialogue: "不要回頭。", background: Background.Chapter_1_Ch1_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "聲音很近，但她聽不出是誰。男的，女的，聽的時候像兩個人疊在一起，分的時候又一個都不是。她正想轉過去看——", background: Background.Chapter_1_Ch1_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "夢斷在這裡。像被剪掉的畫面，後面全部空白。", background: Background.Chapter_1_Ch1_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯又是那個夢。", background: Background.Chapter_1_Ch1_Act1_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她躺著沒動，盯著天花板上一塊水漬的形狀，等呼吸慢下來。那塊水漬她看了七天，形狀沒變過，像一隻張開嘴的魚。", background: Background.Chapter_1_Ch1_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）第七天了。", background: Background.Chapter_1_Ch1_Act1_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她側過身，拿起枕邊的手機。螢幕上的數字很亮。", background: Background.Chapter_1_Ch1_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "6:13。", background: Background.Chapter_1_Ch1_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）六點十三分。", background: Background.Chapter_1_Ch1_Act1_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把這幾個字在心裡念了一遍，像在確認什麼。確認完了，又覺得沒什麼好確認的——每天都是這個時間醒，身體比鬧鐘準。", background: Background.Chapter_1_Ch1_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "牆上那面廉價電子鐘跳了一下，數字比手機快了幾秒。澪瞥了一眼，沒在意。舊鐘本來就不準，電池快沒電的時候會自己偷跑，這棟老公寓裡的東西都這樣，壞得不徹底，又不肯好好活著。", background: Background.Chapter_1_Ch1_Act1_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）起來吧。", background: Background.Chapter_1_Ch1_Act1_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她坐起來的動作很慢，像一具沒上緊發條的東西。腳踩到地板的時候涼意從腳底竄上來，她哆嗦了一下，沒去拿拖鞋，赤腳站了一會兒。", background: Background.Chapter_1_Ch1_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "隔壁那間房沒有聲音。", background: Background.Chapter_1_Ch1_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "本來就該沒有聲音。已經七天了。但每天早上醒來的那一秒，她還是會等——等牆那邊傳來翻身的聲音，等遊戲手把撞到桌角的悶響，等一句含糊的「姐，早安」。", background: Background.Chapter_1_Ch1_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "什麼都沒有。", background: Background.Chapter_1_Ch1_Act1_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪推開悠真的房門。", background: Background.Chapter_1_Ch1_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "門沒鎖。她從不上鎖，悠真也不上鎖。這是他們之間沒說過的規矩——門可以關，但不能鎖。", background: Background.Chapter_1_Ch1_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "房間裡的光是那種早晨才有的灰藍色，從窗簾縫裡漏進來，剛好照到一半的東西，另一半還埋在暗裡。", background: Background.Chapter_1_Ch1_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "校服掛在椅背上，沒收好，袖子垂著，像有人剛起身離開。", background: Background.Chapter_1_Ch1_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "遊戲手把丟在桌上，線纏成一團。", background: Background.Chapter_1_Ch1_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一副便宜耳機繞在床頭欄杆上，海綿套鬆了一邊。", background: Background.Chapter_1_Ch1_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "桌角有一包未拆的零食，包裝袋的角被撕開了一個小口，大概是悠真原本想吃，又忘了。", background: Background.Chapter_1_Ch1_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "攤開的參考書旁邊，一道數學題寫到一半。算式停在倒數第二步，最後一行只寫了個等號，後面是空的——像他算到一半被叫走，或者自己走開了，以為會回來。", background: Background.Chapter_1_Ch1_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "桌角還有一個備用眼鏡盒。", background: Background.Chapter_1_Ch1_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪的視線在那個盒子上停了一下。", background: Background.Chapter_1_Ch1_Act1_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）眼鏡盒還在。", background: Background.Chapter_1_Ch1_Act1_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "悠真有近視，不嚴重，但忘記戴眼鏡會頭痛。出門他一定會帶備用眼鏡盒——這是澪從小唸到大的事，唸到他自己都會嫌煩。", background: Background.Chapter_1_Ch1_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "牆角塞著一雙運動鞋，鞋帶沒解，鞋舌歪向一邊。", background: Background.Chapter_1_Ch1_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "書包靠在床腳，拉鏈沒拉。澪彎腰把它拿起來，翻了一下——裡面夾著一張學校發的說明單，折成四折，角被壓皺了。", background: Background.Chapter_1_Ch1_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「關東青少年睡眠支援計畫」。學校合作的睡眠與壓力研究，免費檢查，附小額獎學金。悠真兩週前帶回來的，澪當時看了一眼，覺得就是普通的校園健康計畫。", background: Background.Chapter_1_Ch1_Act1_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）普通的。", background: Background.Chapter_1_Ch1_Act1_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把說明單折回去，放回書包裡。", background: Background.Chapter_1_Ch1_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這個房間她已經翻過很多次了。書包翻過，抽屜翻過，床底下翻過，連枕頭套都翻過。每次都告訴自己可能找不到新東西，每次還是會再走進來，再翻一遍——像一種停不下來的檢查，明知道門鎖了，還是要伸手去推。", background: Background.Chapter_1_Ch1_Act1_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）今天也找不到吧。", background: Background.Chapter_1_Ch1_Act1_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站在房間中間，沒有坐下。窗外的光慢慢變亮，灰藍色裡滲進一點白。校服的袖子被穿堂風吹動了一下，很輕，像有人剛走過。", background: Background.Chapter_1_Ch1_Act1_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪看著那個晃動的袖口，沒有出聲。", background: Background.Chapter_1_Ch1_Act1_S1 },
];
